class Solution {
    public int minimizedStringLength(String s) {
        int n = s.length();
        int[] left = new int[n], right = new int[n];
        for (int i = 0; i < n; i++) {
            if (i > 0) left[i] = left[i - 1];
            if (s.charAt(i) == s.charAt(0)) left[i]++;
        }
        for (int i = n - 1; i >= 0; i--) {
            if (i < n - 1) right[i] = right[i + 1];
            if (s.charAt(i) == s.charAt(n - 1)) right[i]++;
        }
        int res = n;
        for (int i = 0; i < n; i++) {
            res = Math.min(res, n - left[i] - right[i]);
        }
        return res;
    }
}
